# Exercício 8 - Informações Detalhadas do Processador\n\n# importo as bibliotecas necessárias\nimport psutil      # para informações de hardware\nimport platform    # para informações do SO\nimport os          # para limpar tela\n\n# tentamos importar cpuinfo; se não estiver instalado, usamos apenas psutil\ntry:\n    import cpuinfo\n    tem_cpuinfo = True\nexcept ImportError:\n    tem_cpuinfo = False\n\n# limpo a tela\nos.system(\"cls\")\n\n# exibo um título\nprint(\"=\"*70)\nprint(\"       INFORMAÇÕES DETALHADAS DO PROCESSADOR\")\nprint(\"=\"*70)\n\n# ============================================================\n# Informações básicas com psutil (sem cpuinfo)\n# ============================================================\n\nprint(\"\\n[1] INFORMAÇÕES BÁSICAS:\")\nprint(\"-\" * 70)\n\n# número de núcleos\nnum_nucleos_fisicos = psutil.cpu_count(logical=False)\nnum_nucleos_logicos = psutil.cpu_count(logical=True)\n\nprint(f\"Núcleos Físicos:    {num_nucleos_fisicos}\")\nprint(f\"Núcleos Lógicos:    {num_nucleos_logicos}\")\n\n# frequência da CPU\ncpu_freq = psutil.cpu_freq()\nif cpu_freq:\n    print(f\"Frequência Atual:   {cpu_freq.current:.0f} MHz ({cpu_freq.current/1000:.2f} GHz)\")\n    print(f\"Frequência Máxima:  {cpu_freq.max:.0f} MHz ({cpu_freq.max/1000:.2f} GHz)\")\n    print(f\"Frequência Mínima:  {cpu_freq.min:.0f} MHz ({cpu_freq.min/1000:.2f} GHz)\")\nelse:\n    print(\"Frequência:         Não disponível neste sistema\")\n\n# ============================================================\n# Informações mais detalhadas com cpuinfo\n# ============================================================\n\nif tem_cpuinfo:\n    print(\"\\n[2] INFORMAÇÕES DETALHADAS (cpuinfo):\")\n    print(\"-\" * 70)\n\n    try:\n        # cpuinfo.get_cpu_info() retorna um dicionário com muitas informações\n        info_cpu = cpuinfo.get_cpu_info()\n\n        # nome/modelo da CPU\n        if \"brand_raw\" in info_cpu:\n            print(f\"Modelo da CPU:      {info_cpu['brand_raw']}\")\n        elif \"brand\" in info_cpu:\n            print(f\"Modelo da CPU:      {info_cpu['brand']}\")\n\n        # arquitetura\n        if \"arch\" in info_cpu:\n            print(f\"Arquitetura:        {info_cpu['arch']}\")\n\n        # flags (instruções suportadas)\n        if \"flags\" in info_cpu:\n            flags = info_cpu['flags']\n            print(f\"Flags (primeiras):  {', '.join(flags[:5])}...\")\n            print(f\"Total de flags:     {len(flags)}\")\n\n    except Exception as e:\n        print(f\"Erro ao obter informações com cpuinfo: {e}\")\n\nelse:\n    print(\"\\n[2] INFORMAÇÕES DETALHADAS:\")\n    print(\"-\" * 70)\n    print(\"⚠️  cpuinfo não está instalado.\")\n    print(\"   Para informações detalhadas, instale com: pip install py-cpuinfo\")\n\n# ============================================================\n# Informações do Sistema Operacional\n# ============================================================\n\nprint(\"\\n[3] SISTEMA OPERACIONAL:\")\nprint(\"-\" * 70)\nprint(f\"Sistema:            {platform.system()}\")\nprint(f\"Release:            {platform.release()}\")\nprint(f\"Versão:             {platform.version()}\")\nprint(f\"Processador:        {platform.processor()}\")\n\n# ============================================================\n# Limitações Conhecidas\n# ============================================================\n\nprint(\"\\n[4] LIMITAÇÕES E OBSERVAÇÕES:\")\nprint(\"-\" * 70)\nprint(\"⚠️  Número de Série da CPU:\")\nprint(\"    - Em sistemas Windows, requer permissão de administrador\")\nprint(\"    - Em Linux/macOS, pode não estar disponível\")\nprint(\"    - Muitos sistemas não expõem essa informação por razões de segurança\")\nprint(\"    - Tecnicamente possível via WMI (Windows) ou DMI (Linux)\")\nprint(\"      mas requer ferramentas externas e permissões elevadas\")\nprint(\"\\n⚠️  Precisão das Informações:\")\nprint(\"    - Dados dependem do SO e driver\")\nprint(\"    - Algumas informações podem estar ausentes em VMs\")\nprint(\"    - Frequência pode variar conforme carga e throttling (economia)\")\n\nprint(\"\\n\" + \"=\"*70)\n\n# Anotações:\n# - psutil.cpu_count(logical=False): número de núcleos FÍSICOS\n#   (núcleos reais no processador)\n# - psutil.cpu_count(logical=True): número de núcleos LÓGICOS\n#   (threads; com hyperthreading, pode ser 2x o físico)\n# - psutil.cpu_freq() retorna informações de frequência\n#   * current: frequência atual\n#   * max: frequência máxima suportada\n#   * min: frequência mínima suportada\n# - try/except ImportError trata quando cpuinfo não está instalado\n# - cpuinfo.get_cpu_info() retorna dicionário com MUITO detalhe\n#   * brand_raw: nome completo da CPU\n#   * arch: arquitetura (x86_64, ARM, etc)\n#   * flags: instruções suportadas (SSE, AVX, etc)\n# - platform.system(): retorna o SO (Windows, Linux, Darwin)\n# - Número de série da CPU é notoriamente difícil de obter:\n#   * Windows: pode via WMI se admin\n#   * Linux: via /proc/cpuinfo se disponível\n#   * macOS: via system_profiler mas complexo\n#   por isso é melhor avisar que não está disponível de forma portável\n